    await waitFor(() => expect(result.current.loading).toBe(false))
    // Both have same position — order should be stable (r1 before r2 as received)
    const ids = result.current.cards.ready.map(c => c.id)
    expect(ids).toEqual(['r1', 'r2'])
  })
})

