      const updatedKey = columnToKey(updated.column)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.filter(c => c.id !== id)
        }
        next[updatedKey] = [...next[updatedKey], updated]
          .sort((a, b) => a.position - b.position)
        return next
      })
      return updated
    } catch (err) {
      applyCards(rollback)
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // addComment — temp-ID optimistic pattern
  // -------------------------------------------------------------------------

  const addComment = useCallback(async (cardId, data) => {
    const tempId = nextTempId()
    const optimisticComment = {
      id: tempId,
      card_id: cardId,
      author: data.author,
      content: data.content,
      created_at: Date.now(),
    }

    applyCards(prev => {
      const next = {}
      for (const [k, col] of Object.entries(prev)) {
        next[k] = col.map(c =>
          c.id === cardId
            ? { ...c, comments: [...c.comments, optimisticComment] }
            : c
        )
      }
      return next
    })
    beginOp()

    try {
      const comment = await createComment(cardId, data)
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c =>
            c.id === cardId
              ? {
                  ...c,
                  comments: c.comments
                    .filter(cm => cm.id !== tempId)
                    .concat(comment),
                }
              : c
          )
        }
        return next
      })
      return comment
    } catch (err) {
      applyCards(prev => {
        const next = {}
        for (const [k, col] of Object.entries(prev)) {
          next[k] = col.map(c =>
            c.id === cardId
              ? { ...c, comments: c.comments.filter(cm => cm.id !== tempId) }
              : c
          )
        }
        return next
      })
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // Public interface
  // -------------------------------------------------------------------------

  return {
    cards,
    loading,
    error,
    createCard,
    updateCard,
    deleteCard,
    moveCard,
    addComment,
  }
}

