              : c
          )
        }
        return next
      })
      throw err
    } finally {
      endOp()
    }
  }, [])

  // -------------------------------------------------------------------------
  // Public interface
  // -------------------------------------------------------------------------

  return {
    cards,
    loading,
    error,
    createCard,
    updateCard,
    deleteCard,
    moveCard,
    addComment,
  }
}

