    act(() => simulateWsEvent('card:updated', { id: 'r1', column: 'ready', position: 1, title: 'Second Remote', assignee: null, description: null, created_at: 1000 }))
    expect(result.current.cards.ready[0].title).toBe('Second Remote')
  })
})

